build me the admin management app based on this spec below, combined with the script i uploaded

{
  "app_name": "Skill Lab Training Management",
  "description": "A Google Apps Script Web App to replace Google Forms for training registration. It includes an authenticated Admin Dashboard for data management (Master list, Materi schedule, Recap dashboard) and a public User Interface for submitting training requests.",
  "required_files": [
    "Code.gs",
    "Admin.html",
    "User.html"
  ],
  "data_sources": {
    "type": "Google Spreadsheet",
    "sheets": [
      { "name": "Master", "purpose": "Teacher full names list." },
      { "name": "Materi", "purpose": "Training schedule (Title, Date, Drive Link)." },
      { "name": "Recap", "purpose": "Registration records (Teacher, Course, Confirmation Status, Attendance)." }
    ],
    "external_apis": [
      "Google Form (for dropdown sync)",
      "Calendar (for event creation)",
      "Drive (for folder creation)",
      "Gmail (for email confirmation/attendance)"
    ]
  },
  "backend_functions_code_gs": [
    { 
      "name": "doGet(e)", 
      "purpose": "Web App router. Renders Admin.html if user is authenticated as Admin, else renders User.html.",
      "dependencies": ["getAuthConfig"]
    },
    { 
      "name": "getAuthConfig()", 
      "purpose": "Security. Returns user role ('Admin' or 'User') based on Session.getActiveUser().getEmail() matching the hardcoded ADMIN_EMAIL."
    },
    { 
      "name": "getAllData(sheetName)", 
      "purpose": "Generic data retrieval. Fetches all data rows from a sheet, returning an Array of Objects (using headers as keys)." 
    },
    { 
      "name": "getRecapDashboardData(materiTitle)", 
      "purpose": "Dashboard logic. Summarizes Recap sheet data (total registered, confirmed, attended, absent) filtered by the selected materiTitle." 
    },
    { 
      "name": "submitTrainingRequest(requestData)", 
      "purpose": "User I/O. Writes submission data to the 'Recap' sheet (including name lookup and date lookup) and triggers sendPendingConfirmationEmails()." 
    },
    { 
      "name": "saveMasterList(masterList)", 
      "purpose": "Admin I/O. Overwrites the 'Master' sheet data and triggers updateTeacherDropdown() on the linked Google Form." 
    },
    { 
      "name": "saveMateriList(materiList)", 
      "purpose": "Admin I/O. Overwrites the 'Materi' sheet data and triggers the full syncAllScheduleData() (Form, Calendar, Drive)." 
    }
  ],
  "frontend_admin_html_requirements": [
    "Uses vanilla JavaScript and Google.script.run for communication.",
    "Displays data using HTML tables.",
    "Includes three tabs: Recap Dashboard, Teacher Management, Materi Management.",
    "Recap Dashboard must display the results of getRecapDashboardData(selectedMateri)."
  ],
  "frontend_user_html_requirements": [
    "Uses vanilla JavaScript and Google.script.run for communication.",
    "Form includes dynamic, searchable selection for 'Teacher Name' (from Master list).",
    "Form includes dynamic selection for 'Training Materi' (from Materi list, showing Title and Date).",
    "Submits data using submitTrainingRequest(requestData)."
  ]
}

