export interface Teacher {
  Fullname: string;
  Prefix?: string;
  Nickname?: string;
  Phone?: string;
  Branch?: string;
}

export interface Materi {
  Materi: string;
  Tanggal: string | Date; // Date string or object
  GDrive?: string;
  CalendarStatus?: string;
}

export interface RecapRow {
  Timestamp?: string;
  Teacher: string;
  Email: string;
  Course: string;
  Date: string;
  Confirmation?: string;
  Attendance?: string;
  AttendanceStatus?: string;
  GDrive?: string;
  // New fields
  Prefix?: string;
  Nickname?: string;
  Phone?: string;
  Branch?: string;
}

export interface DashboardStats {
  totalRegistered: number;
  confirmationPending: number;
  attended: number;
  absent: number;
}

export interface AuthConfig {
  email: string;
  role: 'Admin' | 'User';
}

export interface TrainingRequest {
  teacherName: string;
  teacherEmail: string;
  courseTitle: string;
  prefix?: string;
  nickname?: string;
  phone?: string;
  branch?: string;
}

export interface UpdateAttendanceRequest {
  teacherEmail: string;
  courseTitle: string;
  status: 'Hadir' | 'Tidak hadir';
}

export interface ApiResponse<T> {
  success: boolean;
  message?: string;
  data?: T;
}

export const LogoUrl = "https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEh8xFLdJ6RzDqFz_sS6PzT30e3zXk0XyZ_8xFLdJ6RzDqFz_sS6PzT30e3zXk0XyZ_8xFLdJ6RzDqFz_sS6PzT30e3zXk0XyZ_8/s1600/SkillLabLogo.png";

import { AuthConfig, DashboardStats, Materi, RecapRow, Teacher, TrainingRequest, UpdateAttendanceRequest } from "../types";

// Helper for Title Case and Trimming
const cleanString = (str: string) => {
  if (!str) return "";
  return str
    .trim()
    .toLowerCase()
    .split(' ')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

// Mock Data Stores with more detailed info
let mockTeachers: Teacher[] = [
  { Fullname: "Robert Oliviandro Pellokila", Prefix: "Mr.", Nickname: "Robert", Branch: "Denpasar Gatsu", Phone: "62812345678" },
  { Fullname: "I Kadek Adi Yoga Suputra", Prefix: "Mr.", Nickname: "Adi", Branch: "Jimbaran", Phone: "62898765432" },
  { Fullname: "Dewi Santoso", Prefix: "Ms.", Nickname: "Dewi", Branch: "Ubud", Phone: "62855443322" },
  { Fullname: "Michael Chen", Prefix: "Mr.", Nickname: "Michael", Branch: "Gatsu", Phone: "62811111111" },
];

let mockMateri: Materi[] = [
  { Materi: "Classroom Management 101", Tanggal: "2023-11-15T14:00:00.000Z", GDrive: "", CalendarStatus: "Event Created" },
  { Materi: "Advanced Public Speaking", Tanggal: "2023-11-20T14:00:00.000Z", GDrive: "https://drive.google.com/...", CalendarStatus: "Event Created" },
  { Materi: "Digital Literacy for Kids", Tanggal: "2023-12-05T14:00:00.000Z", GDrive: "", CalendarStatus: "" },
];

let mockRecap: RecapRow[] = [
  { Teacher: "Robert", Email: "robert@example.com", Course: "Classroom Management 101", Date: "2023-11-15", Confirmation: "Email sent", Attendance: "Hadir" },
  { Teacher: "Adi", Email: "adi@example.com", Course: "Classroom Management 101", Date: "2023-11-15", Confirmation: "Email sent", Attendance: "Tidak hadir" },
];

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const api = {
  getAuthConfig: async (): Promise<AuthConfig> => {
    await delay(500);
    return { email: 'demo@timedoor.com', role: 'User' };
  },

  getAllData: async (sheetName: 'Master' | 'Materi' | 'Recap'): Promise<any[]> => {
    await delay(600);
    switch (sheetName) {
      case 'Master': 
        return [...mockTeachers].sort((a, b) => (a.Nickname || "").localeCompare(b.Nickname || ""));
      case 'Materi': 
        return [...mockMateri].sort((a, b) => a.Materi.localeCompare(b.Materi));
      case 'Recap': 
        return [...mockRecap];
      default: return [];
    }
  },

  getRecapDashboardData: async (materiTitle: string): Promise<DashboardStats> => {
    await delay(500);
    const filtered = mockRecap.filter(r => r.Course === materiTitle);
    return {
      totalRegistered: filtered.length,
      confirmationPending: filtered.filter(r => !r.Confirmation || r.Confirmation === '').length,
      attended: filtered.filter(r => r.Attendance === 'Hadir').length,
      absent: filtered.filter(r => r.Attendance === 'Tidak hadir').length,
    };
  },

  getParticipantsByCourse: async (materiTitle: string): Promise<RecapRow[]> => {
    await delay(400);
    return mockRecap.filter(r => r.Course === materiTitle);
  },

  submitTrainingRequest: async (data: TrainingRequest) => {
    await delay(1000);
    const course = mockMateri.find(m => m.Materi === data.courseTitle);
    const dateStr = course ? new Date(course.Tanggal).toISOString().split('T')[0] : "";

    const cleanFullname = cleanString(data.teacherName);
    const cleanNickname = cleanString(data.nickname || "");

    // Add to Master if not exists
    const teacherIdx = mockTeachers.findIndex(t => t.Fullname.toLowerCase() === cleanFullname.toLowerCase());
    if (teacherIdx === -1) {
      mockTeachers.push({ 
        Fullname: cleanFullname,
        Prefix: data.prefix,
        Nickname: cleanNickname,
        Phone: data.phone,
        Branch: data.branch
      });
      mockTeachers.sort((a, b) => (a.Nickname || "").localeCompare(b.Nickname || ""));
    }

    mockRecap.push({
      Timestamp: new Date().toISOString(),
      Teacher: cleanNickname || cleanFullname,
      Email: data.teacherEmail,
      Course: data.courseTitle,
      Date: dateStr,
      Confirmation: "Email sent",
      Attendance: "",
      Prefix: data.prefix,
      Nickname: cleanNickname,
      Phone: data.phone,
      Branch: data.branch
    });

    return { success: true, message: "Registered successfully!" };
  },

  updateAttendance: async (data: UpdateAttendanceRequest) => {
    await delay(500);
    const row = mockRecap.find(r => r.Email === data.teacherEmail && r.Course === data.courseTitle);
    if (row) {
      row.Attendance = data.status;
      return { success: true, message: `Attendance marked as ${data.status}` };
    }
    return { success: false, message: "Participant not found" };
  },

  saveMasterList: async (list: Teacher[]) => {
    await delay(800);
    mockTeachers = list.map(t => ({
      ...t,
      Fullname: cleanString(t.Fullname),
      Nickname: cleanString(t.Nickname || "")
    })).sort((a, b) => (a.Nickname || "").localeCompare(b.Nickname || ""));
    return { success: true, message: "Master list updated." };
  },

  saveMateriList: async (list: Materi[]) => {
    await delay(800);
    mockMateri = list.sort((a, b) => a.Materi.localeCompare(b.Materi));
    return { success: true, message: "Schedule updated and synced." };
  },

  triggerEmailSync: async (type: 'Confirmation' | 'Attendance') => {
    await delay(1500);
    return { success: true, message: `${type} emails synced successfully.` };
  }
};

import React, { useEffect, useState } from 'react';
import { Plus, Trash2, Save, Search, User, ExternalLink } from 'lucide-react';
import { api } from '../services/api';
import { Teacher } from '../types';

export const MasterTab: React.FC = () => {
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [filter, setFilter] = useState('');
  const [saving, setSaving] = useState(false);
  const [isDirty, setIsDirty] = useState(false);

  useEffect(() => {
    loadTeachers();
  }, []);

  const loadTeachers = async () => {
    const data = await api.getAllData('Master');
    setTeachers(data);
    setIsDirty(false);
  };

  const handleAdd = () => {
    setTeachers([...teachers, { Fullname: "New Teacher", Prefix: "Mr.", Nickname: "New", Branch: "", Phone: "" }]);
    setIsDirty(true);
  };

  const handleChange = (index: number, field: keyof Teacher, val: string) => {
    const updated = [...teachers];
    updated[index] = { ...updated[index], [field]: val };
    setTeachers(updated);
    setIsDirty(true);
  };

  const handleDelete = (index: number) => {
    const updated = teachers.filter((_, i) => i !== index);
    setTeachers(updated);
    setIsDirty(true);
  };

  const handleSave = async () => {
    setSaving(true);
    await api.saveMasterList(teachers);
    setSaving(false);
    setIsDirty(false);
    loadTeachers(); // Reload to get cleaned and sorted list
    alert("Teacher list updated successfully!");
  };

  const filteredTeachers = teachers.map((t, idx) => ({ ...t, originalIndex: idx }))
    .filter(t => t.Fullname.toLowerCase().includes(filter.toLowerCase()) || (t.Nickname || "").toLowerCase().includes(filter.toLowerCase()))
    .sort((a, b) => (a.Nickname || "").localeCompare(b.Nickname || ""));

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col h-[calc(100vh-12rem)]">
      <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 rounded-t-xl">
        <h3 className="font-semibold text-gray-700 flex items-center gap-2">
          <User className="w-4 h-4" /> Master Teacher List
        </h3>
        <button 
          onClick={handleSave} 
          disabled={!isDirty || saving}
          className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
            isDirty 
              ? 'bg-blue-600 text-white hover:bg-blue-700' 
              : 'bg-gray-200 text-gray-400 cursor-not-allowed'
          }`}
        >
          <Save className="w-4 h-4" />
          {saving ? 'Saving...' : 'Save Changes'}
        </button>
      </div>

      <div className="p-4 bg-white border-b border-gray-100 flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input 
            type="text" 
            placeholder="Search by name or nickname..." 
            className="w-full pl-9 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
            value={filter}
            onChange={e => setFilter(e.target.value)}
          />
        </div>
        <button 
          onClick={handleAdd}
          className="flex items-center gap-2 px-4 py-2 bg-green-50 text-green-700 border border-green-200 rounded-lg text-sm font-medium hover:bg-green-100"
        >
          <Plus className="w-4 h-4" /> Add Teacher
        </button>
      </div>

      <div className="flex-1 overflow-x-auto overflow-y-auto">
        <table className="w-full text-sm text-left text-gray-500 min-w-[800px]">
          <thead className="text-xs text-white uppercase bg-[#2d5a41] sticky top-0 z-10">
            <tr>
              <th scope="col" className="px-4 py-3">Fullname</th>
              <th scope="col" className="px-4 py-3">Prefix</th>
              <th scope="col" className="px-4 py-3">Nickname</th>
              <th scope="col" className="px-4 py-3">Teacher</th>
              <th scope="col" className="px-4 py-3">Branch</th>
              <th scope="col" className="px-4 py-3">Phone</th>
              <th scope="col" className="px-4 py-3">WA</th>
              <th scope="col" className="px-4 py-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {filteredTeachers.map((teacher, idx) => {
              const teacherDisplayName = `${teacher.Prefix || ''} ${teacher.Nickname || ''}`.trim();
              const waLink = teacher.Phone ? `https://wa.me/${teacher.Phone.replace(/\D/g, '')}` : '#';

              return (
                <tr key={idx} className="bg-white hover:bg-gray-50 group">
                  <td className="px-4 py-2">
                    <input 
                      type="text" 
                      value={teacher.Fullname}
                      onChange={(e) => handleChange(teacher.originalIndex, 'Fullname', e.target.value)}
                      className="w-full bg-transparent border-none focus:ring-0 text-gray-900 text-xs font-medium"
                    />
                  </td>
                  <td className="px-4 py-2">
                    <select
                      value={teacher.Prefix}
                      onChange={(e) => handleChange(teacher.originalIndex, 'Prefix', e.target.value)}
                      className="bg-transparent border-none focus:ring-0 text-gray-700 text-xs"
                    >
                      <option value="Mr.">Mr.</option>
                      <option value="Ms.">Ms.</option>
                    </select>
                  </td>
                  <td className="px-4 py-2">
                    <input 
                      type="text" 
                      value={teacher.Nickname}
                      placeholder="Nickname"
                      onChange={(e) => handleChange(teacher.originalIndex, 'Nickname', e.target.value)}
                      className="w-full bg-transparent border-none focus:ring-0 text-gray-900 text-xs"
                    />
                  </td>
                  <td className="px-4 py-2 font-medium text-gray-600 italic text-xs">
                    {teacherDisplayName}
                  </td>
                  <td className="px-4 py-2">
                    <input 
                      type="text" 
                      value={teacher.Branch}
                      placeholder="Branch"
