                      type="text" 
                      value={teacher.Phone}
                      placeholder="Phone"
                      onChange={(e) => handleChange(teacher.originalIndex, 'Phone', e.target.value)}
                      className="w-full bg-transparent border-none focus:ring-0 text-gray-900 text-xs"
                    />
                  </td>
                  <td className="px-4 py-2">
                    {teacher.Phone ? (
                      <a 
                        href={waLink} 
                        target="_blank" 
                        rel="noreferrer"
