export const MasterTab: React.FC = () => {
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [filter, setFilter] = useState('');
  const [saving, setSaving] = useState(false);
  const [isDirty, setIsDirty] = useState(false);
  const [editingTeacher, setEditingTeacher] = useState<{ teacher: Teacher, index: number } | null>(null);

  useEffect(() => {
    loadTeachers();
  }, []);

  const loadTeachers = async () => {
    const data = await api.getAllData('Master');
    setTeachers(data);
    setIsDirty(false);
  };

  const handleAdd = () => {
    const newTeacher = { Fullname: "New Teacher", Prefix: "Mr.", Nickname: "New", Branch: "", Phone: "" };
    setTeachers([...teachers, newTeacher]);
    setIsDirty(true);
    // Auto-open edit modal for new teacher
    setEditingTeacher({ teacher: newTeacher, index: teachers.length });
  };

  const handleDelete = (index: number) => {
    if (confirm("Are you sure you want to remove this teacher?")) {
      const updated = teachers.filter((_, i) => i !== index);
      setTeachers(updated);
      setIsDirty(true);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    await api.saveMasterList(teachers);
    setSaving(false);
    setIsDirty(false);
    loadTeachers();
    alert("Teacher list updated successfully!");
  };

  const handleUpdateFromModal = (updated: Teacher) => {
    if (editingTeacher) {
      const newList = [...teachers];
      newList[editingTeacher.index] = updated;
      setTeachers(newList);
      setIsDirty(true);
      setEditingTeacher(null);
    }
  };

  const filteredTeachers = teachers.map((t, idx) => ({ ...t, originalIndex: idx }))
    .filter(t => 
      t.Fullname.toLowerCase().includes(filter.toLowerCase()) || 
      (t.Nickname || "").toLowerCase().includes(filter.toLowerCase()) ||
      (t.Branch || "").toLowerCase().includes(filter.toLowerCase())
    )
    .sort((a, b) => (a.Nickname || "").localeCompare(b.Nickname || ""));

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col h-[calc(100vh-8rem)]">
      {/* Table Header Section */}
      <div className="p-6 border-b border-gray-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white rounded-t-2xl">
        <div>
          <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
            <User className="w-5 h-5 text-blue-600" /> Master Teacher List
          </h3>
          <p className="text-xs text-gray-500 mt-0.5">Manage teacher profiles and contact information.</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <button 
            onClick={handleSave} 
            disabled={!isDirty || saving}
            className={`flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all shadow-lg ${
              isDirty 
                ? 'bg-[#2d5a41] text-white hover:bg-[#254a35] shadow-green-100' 
                : 'bg-gray-100 text-gray-400 cursor-not-allowed shadow-none'
            }`}
          >
            <Save className="w-4 h-4" />
            {saving ? 'Saving...' : 'Save Changes'}
          </button>
        </div>
      </div>

      {/* Filter/Add Row */}
      <div className="p-4 bg-gray-50/50 border-b border-gray-100 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input 
            type="text" 
            placeholder="Search by name, nickname, or branch..." 
            className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all"
            value={filter}
            onChange={e => setFilter(e.target.value)}
          />
        </div>
        <button 
          onClick={handleAdd}
          className="flex items-center justify-center gap-2 px-5 py-2.5 bg-white text-blue-600 border border-blue-200 rounded-xl text-sm font-bold hover:bg-blue-50 transition-colors shadow-sm"
        >
          <Plus className="w-4 h-4" /> Add Teacher
        </button>
      </div>

      {/* Table Container */}
      <div className="flex-1 overflow-x-auto overflow-y-auto">
        <table className="w-full text-sm text-left border-collapse">
          <thead className="bg-[#2d5a41] text-white sticky top-0 z-10">
            <tr>
              <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-xs">Teacher</th>
              <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-xs">Fullname</th>
              <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-xs">Branch</th>
              <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-xs">Phone</th>
              <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-xs">WA</th>
              <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-xs text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100 bg-white">
            {filteredTeachers.map((teacher, idx) => {
              const teacherDisplayName = `${teacher.Prefix || ''} ${teacher.Nickname || ''}`.trim();
              const waLink = teacher.Phone ? `https://wa.me/${teacher.Phone.replace(/\D/g, '')}` : '#';

              return (
                <tr 
                  key={idx} 
                  className="hover:bg-blue-50/30 group transition-colors cursor-pointer"
                  onClick={() => setEditingTeacher({ teacher, index: teacher.originalIndex })}
                >
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                       <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 text-xs font-bold uppercase">
                        {(teacher.Nickname || 'T')[0]}
                       </div>
                       <span className="font-bold text-gray-800 italic">{teacherDisplayName}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-gray-600">
                    {teacher.Fullname}
                  </td>
                  <td className="px-6 py-4">
                    <span className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-gray-100 text-gray-700 rounded-lg text-xs font-medium">
                      <MapPin className="w-3 h-3 text-gray-400" /> {teacher.Branch || '-'}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-gray-500 font-mono text-xs">
                    {teacher.Phone || '-'}
                  </td>
                  <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                    {teacher.Phone ? (
                      <a 
                        href={waLink} 
                        target="_blank" 
                        rel="noreferrer"
                        className="text-blue-600 hover:text-blue-800 font-bold flex items-center gap-1 text-xs hover:underline decoration-blue-300"
                      >
                        WA {teacherDisplayName}
                      </a>
                    ) : <span className="text-gray-300">-</span>}
                  </td>
                  <td className="px-6 py-4 text-right" onClick={(e) => e.stopPropagation()}>
                    <button 
                      onClick={() => handleDelete(teacher.originalIndex)}
                      className="text-gray-300 hover:text-red-500 p-2 rounded-xl transition-all hover:bg-red-50"
                      title="Remove"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              );
            })}
            {filteredTeachers.length === 0 && (
              <tr>
                <td colSpan={6} className="px-6 py-20 text-center text-gray-400 italic bg-gray-50/30">
                  <div className="flex flex-col items-center gap-3">
                    <Search className="w-8 h-8 text-gray-200" />
                    <p>No teachers found matching your search.</p>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {editingTeacher && (
        <EditTeacherModal 
          teacher={editingTeacher.teacher} 
          onClose={() => setEditingTeacher(null)} 
          onSave={handleUpdateFromModal} 
        />
      )}
    </div>
  );
};

