          <h3 className="text-xl font-bold text-gray-800 flex items-center gap-2">
            <User className="w-6 h-6 text-[#2d5a41]" /> Master Teacher List
          </h3>
          <p className="text-xs text-gray-500 mt-1">Manage teacher records and database information.</p>
        </div>
        <div className="w-full md:w-auto">
          <button 
            type="button"
            onClick={handleSave} 
            disabled={!isDirty || saving}
            className={`w-full flex items-center justify-center gap-2 px-8 py-3 rounded-xl text-sm font-bold transition-all shadow-lg ${
              isDirty 
                ? 'bg-[#2d5a41] text-white hover:bg-[#254a35] shadow-green-100 active:scale-95' 
                : 'bg-gray-100 text-gray-400 cursor-not-allowed shadow-none'
            }`}
          >
            <Save className="w-4 h-4" />
            {saving ? 'Saving...' : 'Save Changes'}
          </button>
        </div>
      </div>

      {/* Toolbar */}
      <div className="p-4 bg-gray-50/40 border-b border-gray-100 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
