            type="text" 
            placeholder="Search by name, nickname, or branch..." 
            className="w-full pl-10 pr-10 py-2.5 bg-white border border-gray-200 rounded-xl text-sm text-gray-800 focus:ring-2 focus:ring-[#2d5a41]/10 focus:border-[#2d5a41] outline-none transition-all shadow-sm"
            value={filter}
