/**
 * Utility to call Google Apps Script server functions as Promises.
 * This assumes the .gs file has corresponding functions defined.
 */
const run = (funcName: string, ...args: any[]): Promise<any> => {
  return new Promise((resolve, reject) => {
    // Check if running in Google Apps Script environment
    if (typeof google !== 'undefined' && google.script && google.script.run) {
      google.script.run
        .withSuccessHandler(resolve)
        .withFailureHandler(reject)
        [funcName](...args);
    } else {
      console.error(`Google Apps Script environment not detected. Cannot execute: ${funcName}`);
      reject(new Error("Environment Error: google.script.run is not available."));
    }
  });
};

