export const MasterTab: React.FC = () => {
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [filter, setFilter] = useState('');
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [isDirty, setIsDirty] = useState(false);
  const [editingTeacher, setEditingTeacher] = useState<{ teacher: Teacher, index: number } | null>(null);

  useEffect(() => {
    loadTeachers();
  }, []);

  const loadTeachers = async () => {
    setLoading(true);
    try {
      const data = await api.getAllData('Master');
      setTeachers(data || []);
      setIsDirty(false);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = () => {
    const newTeacher: Teacher = { Fullname: "New Teacher", Prefix: "Mr.", Nickname: "New", Branch: "", Phone: "" };
    setTeachers(prev => {
      const newList = [...prev, newTeacher];
      setEditingTeacher({ teacher: newTeacher, index: newList.length - 1 });
      return newList;
    });
    setIsDirty(true);
  };

  const handleDelete = (originalIndex: number) => {
    if (confirm("Permanently remove this teacher from the database?")) {
      setTeachers(prev => {
        const updated = prev.filter((_, i) => i !== originalIndex);
        return updated;
      });
      setIsDirty(true);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await api.saveMasterList(teachers);
      setIsDirty(false);
      await loadTeachers();
      alert("Changes synchronized with Spreadsheet successfully.");
    } catch (error) {
      alert("Failed to sync changes.");
    } finally {
      setSaving(false);
    }
  };

  const handleUpdateFromModal = (updated: Teacher) => {
    if (editingTeacher) {
      setTeachers(prev => {
        const newList = [...prev];
        newList[editingTeacher.index] = updated;
        return newList;
      });
      setIsDirty(true);
      setEditingTeacher(null);
    }
  };

  const filteredTeachers = teachers
    .map((t, idx) => ({ ...t, originalIndex: idx }))
    .filter(t => 
      t.Fullname.toLowerCase().includes(filter.toLowerCase()) || 
      (t.Nickname || "").toLowerCase().includes(filter.toLowerCase()) ||
      (t.Branch || "").toLowerCase().includes(filter.toLowerCase())
    )
    .sort((a, b) => (a.Nickname || "").localeCompare(b.Nickname || ""));

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col h-[calc(100vh-8rem)]">
      {/* Table Header Section */}
      <div className="p-6 border-b border-gray-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white rounded-t-2xl">
        <div>
          <h3 className="text-xl font-bold text-gray-800 flex items-center gap-2">
            <User className="w-6 h-6 text-[#2d5a41]" /> Master Teacher List
          </h3>
          <p className="text-xs text-gray-500 mt-1">Manage teacher records and database information.</p>
        </div>
        <div className="w-full md:w-auto">
          <button 
            type="button"
            onClick={handleSave} 
            disabled={!isDirty || saving}
            className={`w-full flex items-center justify-center gap-2 px-8 py-3 rounded-xl text-sm font-bold transition-all shadow-lg ${
              isDirty 
                ? 'bg-[#2d5a41] text-white hover:bg-[#254a35] shadow-green-100 active:scale-95' 
                : 'bg-gray-100 text-gray-400 cursor-not-allowed shadow-none'
            }`}
          >
            <Save className="w-4 h-4" />
            {saving ? 'Syncing...' : 'Save Changes'}
          </button>
        </div>
      </div>

      {/* Toolbar Area */}
      <div className="p-4 bg-gray-50/40 border-b border-gray-100 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input 
            type="text" 
            placeholder="Search by name, nickname, or branch..." 
            className="w-full pl-10 pr-10 py-2.5 bg-white border border-gray-200 rounded-xl text-sm text-gray-800 focus:ring-2 focus:ring-[#2d5a41]/10 focus:border-[#2d5a41] outline-none transition-all shadow-sm"
            value={filter}
            onChange={e => setFilter(e.target.value)}
          />
          {filter && (
            <button 
              onClick={() => setFilter('')}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-700 transition-colors p-1"
            >
              <X className="w-4 h-4" />
            </button>
          )}
        </div>
        <button 
          type="button"
          onClick={handleAdd}
          className="flex items-center justify-center gap-2 px-6 py-2.5 bg-white text-[#2d5a41] border border-[#2d5a41]/20 rounded-xl text-sm font-bold hover:bg-green-50 transition-all shadow-sm active:scale-95"
        >
          <Plus className="w-4 h-4" /> Add Teacher
        </button>
      </div>

      {/* Table Section */}
      <div className="flex-1 overflow-x-auto overflow-y-auto scrollbar-hide">
        {loading ? (
          <div className="flex flex-col items-center justify-center h-64 gap-3 text-gray-400">
            <div className="w-8 h-8 border-4 border-[#2d5a41]/20 border-t-[#2d5a41] rounded-full animate-spin"></div>
            <p className="text-sm font-medium">Fetching records...</p>
          </div>
        ) : (
          <table className="w-full text-sm text-left border-collapse">
            <thead className="bg-[#2d5a41] text-white sticky top-0 z-10 shadow-sm">
              <tr>
                <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-[10px]">Teacher</th>
                <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-[10px]">Fullname</th>
                <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-[10px]">Branch</th>
                <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-[10px]">WA Link</th>
                <th scope="col" className="px-6 py-4 font-bold uppercase tracking-wider text-[10px] text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 bg-white">
              {filteredTeachers.map((teacher) => {
                const teacherDisplayName = `${teacher.Prefix || ''} ${teacher.Nickname || ''}`.trim();
                const waLink = teacher.Phone ? `https://wa.me/${teacher.Phone.replace(/\D/g, '')}` : '#';

                return (
                  <tr 
                    key={teacher.originalIndex} 
                    className="hover:bg-[#2d5a41]/5 group transition-colors cursor-pointer"
                    onClick={() => setEditingTeacher({ teacher, index: teacher.originalIndex })}
                  >
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-full bg-blue-50 flex items-center justify-center text-blue-600 text-[10px] font-bold uppercase ring-1 ring-blue-100">
                          {(teacher.Nickname || 'T')[0]}
                         </div>
                         <span className="font-bold text-gray-800 italic">{teacherDisplayName}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-gray-600">
                      {teacher.Fullname}
                    </td>
                    <td className="px-6 py-4">
                      <span className="inline-flex items-center gap-1.5 px-3 py-1 bg-gray-100 text-gray-700 rounded-lg text-xs font-medium border border-gray-200">
                        <MapPin className="w-3 h-3 text-gray-400" /> {teacher.Branch || '-'}
                      </span>
                    </td>
                    <td className="px-6 py-4" onClick={(e) => e.stopPropagation()}>
                      {teacher.Phone ? (
                        <a 
                          href={waLink} 
                          target="_blank" 
                          rel="noreferrer"
                          className="text-blue-600 hover:text-blue-800 font-bold flex items-center gap-1.5 text-xs hover:underline decoration-blue-300 transition-colors"
                        >
                          WA {teacherDisplayName}
                        </a>
                      ) : <span className="text-gray-300">-</span>}
                    </td>
                    <td className="px-6 py-4 text-right" onClick={(e) => e.stopPropagation()}>
                      <button 
                        type="button"
                        onClick={() => handleDelete(teacher.originalIndex)}
