                      >
                        <Trash2 className="w-4.5 h-4.5" />
                      </button>
                    </td>
                  </tr>
                );
              })}
              {filteredTeachers.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-24 text-center text-gray-400 italic bg-gray-50/20">
                    <div className="flex flex-col items-center gap-4">
                      <Search className="w-12 h-12 text-gray-200" />
                      <p className="text-sm">No teacher records found.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>

      {/* Edit Modal Overlay */}
      {editingTeacher && (
        <EditTeacherModal 
          teacher={editingTeacher.teacher} 
          onClose={() => setEditingTeacher(null)} 
          onSave={handleUpdateFromModal} 
        />
      )}
    </div>
  );
};

import { AuthConfig, DashboardStats, Materi, RecapRow, Teacher, TrainingRequest, UpdateAttendanceRequest } from "../types";

// Global declaration for GAS environment
declare const google: any;

// Backend IDs provided by user
export const GFORM_ID = "1X2wRn2oEfnq_BEawNSHuuCS5YHlS47dOiK4AxRQCMEk";
export const GSHEET_ID = "1ANeS6kcrHZWPFDZvuaMs4ikJO-2jn6fzYIBzjJISq7U";
export const GDRIVE_FOLDER_ID = "1CNFQCC7ggINYQTiUDw8hulf8B6WNH9MA";

/**
 * Robust runner that calls GAS if available, 
 * otherwise uses a local simulation to prevent crashes and allow dev testing.
 */
const run = async (funcName: string, ...args: any[]): Promise<any> => {
  // Check if we are in the real Google Apps Script environment
  const isGAS = typeof google !== 'undefined' && google.script && google.script.run;

  if (isGAS) {
    return new Promise((resolve, reject) => {
      google.script.run
        .withSuccessHandler(resolve)
        .withFailureHandler(reject)
        [funcName](...args);
    });
  }

  // FALLBACK: Local Simulation for Preview/Development Mode
  console.warn(`GAS environment not detected. Simulating [${funcName}] locally.`);
  await new Promise(r => setTimeout(r, 400)); // Simulate network latency

  const getStore = (key: string) => JSON.parse(localStorage.getItem(`skill_lab_${key}`) || '[]');
  const setStore = (key: string, data: any) => localStorage.setItem(`skill_lab_${key}`, JSON.stringify(data));

  switch (funcName) {
    case 'getAuthConfig':
      return { email: 'master@skilllab.td', role: 'Admin' };

    case 'getAllData': {
      const sheetName = args[0];
      let data = getStore(sheetName);
      if (data.length === 0) {
        // Initialize with default data if empty
        if (sheetName === 'Master') data = [
          { Fullname: "Michael Chen", Prefix: "Mr.", Nickname: "Michael", Branch: "Gatsu", Phone: "62811111111" },
          { Fullname: "Robert Oliviandro Pellokila", Prefix: "Mr.", Nickname: "Robert", Branch: "Denpasar Gatsu", Phone: "62812345678" }
        ];
        if (sheetName === 'Materi') data = [
          { Materi: "Classroom Management", Tanggal: new Date().toISOString() },
          { Materi: "Public Speaking", Tanggal: new Date().toISOString() }
        ];
        setStore(sheetName, data);
      }
      return data;
    }

    case 'submitTrainingRequest': {
      const data: TrainingRequest = args[0];
      // If it's a new teacher, add to Master list
      if (data.prefix && data.nickname) {
        const master = getStore('Master');
        const exists = master.some((t: Teacher) => t.Fullname.toLowerCase() === data.teacherName.toLowerCase());
        if (!exists) {
          master.push({
            Fullname: data.teacherName,
            Prefix: data.prefix,
            Nickname: data.nickname,
            Phone: data.phone,
            Branch: data.branch
          });
          setStore('Master', master);
        }
      }

      // Add to Recap
      const recap = getStore('Recap');
      recap.push({
        Timestamp: new Date().toISOString(),
        Teacher: data.nickname || data.teacherName,
        Email: data.teacherEmail,
        Course: data.courseTitle,
        Date: new Date().toISOString().split('T')[0],
        Confirmation: "Email sent",
        Attendance: ""
      });
      setStore('Recap', recap);
      return { success: true };
    }

    case 'saveMasterList':
      setStore('Master', args[0]);
      return { success: true };

    case 'saveMateriList':
      setStore('Materi', args[0]);
      return { success: true };

    case 'getRecapDashboardData':
      return { totalRegistered: 10, confirmationPending: 2, attended: 5, absent: 3 };

    case 'getParticipantsByCourse': {
      const course = args[0];
      const recap = getStore('Recap');
      return recap.filter((r: RecapRow) => r.Course === course);
    }

    case 'triggerEmailSync':
      return { success: true, message: `${args[0]} synced successfully (simulated).` };

    default:
      return { success: true };
  }
};

