export const UserView: React.FC = () => {
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [materiList, setMateriList] = useState<Materi[]>([]);

  const [formData, setFormData] = useState({
    name: '',
    email: 'teacher@timedoor.net',
    course: '',
    prefix: 'Mr.',
    nickname: '',
    phone: '',
    branch: ''
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [isNewTeacher, setIsNewTeacher] = useState(false);

  const dropdownRef = useRef<HTMLDivElement>(null);

  const fetchData = async () => {
    const [tData, mData] = await Promise.all([
      api.getAllData('Master'),
      api.getAllData('Materi')
    ]);
    setTeachers(tData);

    const sortedMateri = mData
      .filter(m => !isNaN(new Date(m.Tanggal).getTime()))
      .sort((a, b) => a.Materi.localeCompare(b.Materi));

    setMateriList(sortedMateri);
  };

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (!searchTerm) {
      setIsNewTeacher(false);
      return;
    }
    const match = teachers.some(t => t.Fullname.toLowerCase() === searchTerm.toLowerCase());
    setIsNewTeacher(!match);
  }, [searchTerm, teachers]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.course) return;

    if (isNewTeacher) {
      if (!formData.phone || !formData.branch || !formData.nickname) {
        alert("Please fill in all additional fields for new registration.");
        return;
      }
    }

    setIsSubmitting(true);
    await api.submitTrainingRequest({
      teacherName: formData.name,
      teacherEmail: formData.email,
      courseTitle: formData.course,
      prefix: isNewTeacher ? formData.prefix : undefined,
      nickname: isNewTeacher ? formData.nickname : undefined,
      phone: isNewTeacher ? formData.phone : undefined,
      branch: isNewTeacher ? formData.branch : undefined,
    });

    setIsSubmitting(false);
    setSubmitted(true);
  };

  const filteredTeachers = teachers.filter(t => 
    t.Fullname.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleTeacherSelect = (name: string) => {
    setFormData({ ...formData, name: name });
    setSearchTerm(name);
    setDropdownOpen(false);
  };

  const handleReset = () => {
    setSubmitted(false); 
    setFormData({name:'', email:'teacher@timedoor.net', course:'', prefix:'Mr.', nickname:'', phone:'', branch:''}); 
    setSearchTerm(''); 
    fetchData(); // Ensure teachers list is updated with any new registration
  };

  if (submitted) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
        <div className="bg-white max-w-md w-full rounded-2xl shadow-lg p-8 text-center border border-green-100">
          <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <CheckCircle2 className="w-8 h-8" />
          </div>
          <h2 className="text-2xl font-bold text-gray-800 mb-2">Registration Complete!</h2>
          <p className="text-gray-600 mb-6">
            Thank you, {formData.name}. We have received your request for <strong>{formData.course}</strong>.
            Please check your email for confirmation details.
          </p>
          <button 
            onClick={handleReset}
            className="text-blue-600 font-medium hover:underline"
          >
            Register for another session
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md mx-auto">
        <Logo />

        <div className="text-center mb-10">
          <h1 className="text-3xl font-bold text-gray-900">Training Registration</h1>
          <p className="mt-2 text-gray-600">Register your attendance for upcoming sessions.</p>
        </div>

        <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-gray-100">
          <div className="h-2 bg-blue-600 w-full"></div>
          <form onSubmit={handleSubmit} className="p-8 space-y-6">
            <div className="bg-gray-50 p-4 rounded-xl border border-gray-200">
               <div className="flex items-center gap-2 text-sm text-gray-500 mb-1">
                 <Mail className="w-4 h-4" />
                 <span>Verified Email</span>
               </div>
               <div className="font-medium text-gray-800">{formData.email}</div>
               <div className="text-xs text-gray-400 mt-1">Recorded automatically</div>
            </div>

            <div className="relative" ref={dropdownRef}>
              <label className="block text-sm font-medium text-gray-700 mb-2">Full Name</label>
              <div 
                className="relative group cursor-pointer"
                onClick={() => setDropdownOpen(true)}
              >
                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                  <User className="w-4 h-4" />
                </div>
                <input
                  type="text"
                  placeholder="Select or type your name..."
                  className="w-full pl-10 pr-10 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow cursor-text"
                  value={searchTerm}
                  onChange={(e) => {
                    setSearchTerm(e.target.value);
                    setFormData({...formData, name: e.target.value});
                    setDropdownOpen(true);
                  }}
                  autoComplete="off"
                />
                <div className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none group-hover:text-blue-500 transition-colors">
                  <ChevronDown className={`w-5 h-5 transition-transform ${dropdownOpen ? 'rotate-180' : ''}`} />
                </div>
              </div>

              {dropdownOpen && (
                <div className="absolute z-20 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg max-h-60 overflow-auto">
                  {filteredTeachers.length > 0 ? (
                    filteredTeachers.map((t, idx) => (
                      <button
                        key={idx}
                        type="button"
                        className="w-full text-left px-4 py-3 hover:bg-blue-50 text-gray-700 text-sm border-b border-gray-50 last:border-0 flex items-center justify-between group"
                        onClick={() => handleTeacherSelect(t.Fullname)}
                      >
                        {t.Fullname}
                      </button>
                    ))
                  ) : (
                    <div className="px-4 py-3 text-sm text-gray-500 italic bg-gray-50">
                      Name not found. Please fill in details below.
                    </div>
                  )}
                </div>
              )}
            </div>

            {isNewTeacher && searchTerm.length > 0 && (
              <div className="space-y-4 p-5 bg-blue-50 rounded-xl border border-blue-100 animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-2 text-blue-700 font-medium text-sm mb-2">
                   <User className="w-4 h-4" />
                   New Registration Details
                </div>

                <div className="grid grid-cols-3 gap-4">
                  <div className="col-span-1">
                    <label className="block text-xs font-medium text-gray-600 mb-1">Prefix</label>
                    <select
                       className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                       value={formData.prefix}
                       onChange={e => setFormData({...formData, prefix: e.target.value})}
                    >
                      <option value="Mr.">Mr.</option>
                      <option value="Ms.">Ms.</option>
                    </select>
                  </div>
                  <div className="col-span-2">
                    <label className="block text-xs font-medium text-gray-600 mb-1">Nickname</label>
                    <input
                      type="text"
                      required
                      placeholder="e.g. Andy"
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.nickname}
                      onChange={e => setFormData({...formData, nickname: e.target.value})}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-600 mb-1">Phone Number</label>
                  <div className="relative">
                    <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                      <Hash className="w-3 h-3" />
                    </div>
                    <input
                      type="tel"
                      required
                      placeholder="e.g. 08123456789"
                      className="w-full pl-8 pr-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.phone}
                      onChange={e => {
                         const val = e.target.value.replace(/\D/g, '');
                         setFormData({...formData, phone: val});
                      }}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-600 mb-1">Branch</label>
                  <div className="relative">
                    <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                      <MapPin className="w-3 h-3" />
                    </div>
                    <input
                      type="text"
                      required
                      placeholder="e.g. Bali - Renon"
                      className="w-full pl-8 pr-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.branch}
                      onChange={e => setFormData({...formData, branch: e.target.value})}
                    />
                  </div>
                </div>
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Training Topic</label>
              <div className="space-y-3">
                {materiList.map((m, idx) => {
                   const date = new Date(m.Tanggal);
                   const dateStr = date.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' });
                   return (
                    <label 
                      key={idx} 
                      className={`block relative border rounded-xl p-4 cursor-pointer transition-all ${
                        formData.course === m.Materi 
                          ? 'border-blue-600 bg-blue-50 ring-1 ring-blue-600' 
                          : 'border-gray-200 hover:border-blue-300 hover:bg-gray-50'
                      }`}
                    >
                      <input
                        type="radio"
                        name="course"
                        className="sr-only"
                        value={m.Materi}
                        onChange={() => setFormData({...formData, course: m.Materi})}
                      />
                      <div className="flex justify-between items-center">
                        <span className="font-medium text-gray-900">{m.Materi}</span>
                        {formData.course === m.Materi && <CheckCircle2 className="w-5 h-5 text-blue-600" />}
                      </div>
                      <div className="text-sm text-gray-500 mt-1">{dateStr}</div>
                    </label>
                   );
                })}
              </div>
            </div>

            <button
              type="submit"
              disabled={isSubmitting || !formData.name || !formData.email || !formData.course}
              className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white py-3 px-4 rounded-xl font-semibold hover:bg-blue-700 disabled:opacity-50 transition-all shadow-lg shadow-blue-200"
            >
              {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
              {isSubmitting ? 'Processing...' : 'Submit Registration'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

