        api.getAllData('Materi')
      ]);
      setTeachers(tData || []);

      const sortedMateri = (mData || [])
        .filter(m => m && m.Tanggal && !isNaN(new Date(m.Tanggal).getTime()))
        .sort((a, b) => (a.Materi || "").localeCompare(b.Materi || ""));

      setMateriList(sortedMateri);
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (!searchTerm) {
      setIsNewTeacher(false);
      return;
    }
    const match = teachers.some(t => t && t.Fullname && t.Fullname.toLowerCase() === searchTerm.toLowerCase());
    setIsNewTeacher(!match);
  }, [searchTerm, teachers]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.course) return;

    if (isNewTeacher) {
      if (!formData.phone || !formData.branch || !formData.nickname) {
        alert("Please fill in all additional fields for new registration.");
        return;
      }
    }

    setIsSubmitting(true);
    try {
      await api.submitTrainingRequest({
        teacherName: formData.name,
        teacherEmail: formData.email,
        courseTitle: formData.course,
        prefix: isNewTeacher ? formData.prefix : undefined,
        nickname: isNewTeacher ? formData.nickname : undefined,
        phone: isNewTeacher ? formData.phone : undefined,
        branch: isNewTeacher ? formData.branch : undefined,
      });
      setSubmitted(true);
    } catch (error) {
      alert("Submission failed. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const filteredTeachers = teachers.filter(t => 
    t && t.Fullname && t.Fullname.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleTeacherSelect = (name: string) => {
    setFormData({ ...formData, name: name });
    setSearchTerm(name);
    setDropdownOpen(false);
  };

  const handleReset = () => {
    setSubmitted(false); 
    setFormData({name:'', email:'teacher@timedoor.net', course:'', prefix:'Mr.', nickname:'', phone:'', branch:''}); 
    setSearchTerm(''); 
    fetchData();
  };

  if (submitted) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
        <div className="bg-white max-w-md w-full rounded-2xl shadow-lg p-8 text-center border border-green-100">
          <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <CheckCircle2 className="w-8 h-8" />
          </div>
          <h2 className="text-2xl font-bold text-gray-800 mb-2">Registration Complete!</h2>
          <p className="text-gray-600 mb-6">
            Thank you, {formData.name}. We have received your request for <strong>{formData.course}</strong>.
            Please check your email for confirmation details.
          </p>
          <button 
            onClick={handleReset}
            className="text-blue-600 font-medium hover:underline"
          >
            Register for another session
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md mx-auto">
        <Logo />

        <div className="text-center mb-10">
          <h1 className="text-3xl font-bold text-gray-900">Training Registration</h1>
          <p className="mt-2 text-gray-600">Register your attendance for upcoming sessions.</p>
        </div>

        <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-gray-100">
          <div className="h-2 bg-blue-600 w-full"></div>
          <form onSubmit={handleSubmit} className="p-8 space-y-6">
            <div className="bg-gray-50 p-4 rounded-xl border border-gray-200">
               <div className="flex items-center gap-2 text-sm text-gray-500 mb-1">
                 <Mail className="w-4 h-4" />
                 <span>Verified Email</span>
               </div>
               <div className="font-medium text-gray-800">{formData.email}</div>
               <div className="text-xs text-gray-400 mt-1">Recorded automatically</div>
            </div>

            <div className="relative" ref={dropdownRef}>
              <label className="block text-sm font-medium text-gray-700 mb-2">Full Name</label>
              <div 
                className="relative group cursor-pointer"
                onClick={() => setDropdownOpen(true)}
              >
                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                  <User className="w-4 h-4" />
                </div>
                <input
                  type="text"
                  placeholder="Select or type your name..."
                  className="w-full pl-10 pr-10 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-shadow cursor-text"
                  value={searchTerm}
                  onChange={(e) => {
                    setSearchTerm(e.target.value);
                    setFormData({...formData, name: e.target.value});
                    setDropdownOpen(true);
                  }}
                  autoComplete="off"
                />
                <div className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none group-hover:text-blue-500 transition-colors">
                  <ChevronDown className={`w-5 h-5 transition-transform ${dropdownOpen ? 'rotate-180' : ''}`} />
                </div>
              </div>

              {dropdownOpen && (
                <div className="absolute z-20 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg max-h-60 overflow-auto">
                  {filteredTeachers.length > 0 ? (
                    filteredTeachers.map((t, idx) => (
                      <button
                        key={idx}
                        type="button"
                        className="w-full text-left px-4 py-3 hover:bg-blue-50 text-gray-700 text-sm border-b border-gray-50 last:border-0 flex items-center justify-between group"
                        onClick={() => handleTeacherSelect(t.Fullname)}
                      >
                        {t.Fullname}
                      </button>
                    ))
                  ) : (
                    <div className="px-4 py-3 text-sm text-gray-500 italic bg-gray-50">
                      Name not found. Please fill in details below.
                    </div>
                  )}
                </div>
              )}
            </div>

            {isNewTeacher && searchTerm.length > 0 && (
              <div className="space-y-4 p-5 bg-blue-50 rounded-xl border border-blue-100 animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-2 text-blue-700 font-medium text-sm mb-2">
                   <User className="w-4 h-4" />
                   New Registration Details
                </div>

                <div className="grid grid-cols-3 gap-4">
                  <div className="col-span-1">
                    <label className="block text-xs font-medium text-gray-600 mb-1">Prefix</label>
                    <select
                       className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                       value={formData.prefix}
                       onChange={e => setFormData({...formData, prefix: e.target.value})}
                    >
                      <option value="Mr.">Mr.</option>
                      <option value="Ms.">Ms.</option>
                    </select>
                  </div>
                  <div className="col-span-2">
                    <label className="block text-xs font-medium text-gray-600 mb-1">Nickname</label>
                    <input
                      type="text"
                      required
                      placeholder="e.g. Andy"
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.nickname}
                      onChange={e => setFormData({...formData, nickname: e.target.value})}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-600 mb-1">Phone Number</label>
                  <div className="relative">
                    <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                      <Hash className="w-3 h-3" />
                    </div>
                    <input
                      type="tel"
                      required
                      placeholder="e.g. 08123456789"
                      className="w-full pl-8 pr-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.phone}
                      onChange={e => {
                         const val = e.target.value.replace(/\D/g, '');
                         setFormData({...formData, phone: val});
                      }}
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium text-gray-600 mb-1">Branch</label>
                  <div className="relative">
                    <div className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                      <MapPin className="w-3 h-3" />
                    </div>
                    <input
                      type="text"
                      required
                      placeholder="e.g. Bali - Renon"
                      className="w-full pl-8 pr-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                      value={formData.branch}
                      onChange={e => setFormData({...formData, branch: e.target.value})}
                    />
                  </div>
                </div>
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">Training Topic</label>
              <div className="space-y-3">
                {materiList.map((m, idx) => {
                   const date = new Date(m.Tanggal);
                   const dateStr = !isNaN(date.getTime()) 
                    ? date.toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' })
                    : 'Date TBD';
                   return (
                    <label 
                      key={idx} 
                      className={`block relative border rounded-xl p-4 cursor-pointer transition-all ${
                        formData.course === m.Materi 
                          ? 'border-blue-600 bg-blue-50 ring-1 ring-blue-600' 
                          : 'border-gray-200 hover:border-blue-300 hover:bg-gray-50'
                      }`}
                    >
                      <input
                        type="radio"
                        name="course"
                        className="sr-only"
                        value={m.Materi}
                        onChange={() => setFormData({...formData, course: m.Materi})}
                      />
                      <div className="flex justify-between items-center">
                        <span className="font-medium text-gray-900">{m.Materi}</span>
                        {formData.course === m.Materi && <CheckCircle2 className="w-5 h-5 text-blue-600" />}
                      </div>
                      <div className="text-sm text-gray-500 mt-1">{dateStr}</div>
                    </label>
                   );
                })}
                {materiList.length === 0 && !isSubmitting && (
                   <p className="text-sm text-gray-400 italic py-4 text-center">No upcoming training sessions found.</p>
                )}
              </div>
            </div>

            <button
              type="submit"
              disabled={isSubmitting || !formData.name || !formData.email || !formData.course}
              className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white py-3 px-4 rounded-xl font-semibold hover:bg-blue-700 disabled:opacity-50 transition-all shadow-lg shadow-blue-200"
            >
              {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
              {isSubmitting ? 'Processing...' : 'Submit Registration'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { Plus, Trash2, Save, Calendar, ExternalLink, Clock, ChevronLeft, ChevronRight, Edit2 } from 'lucide-react';
import { api } from '../services/api';
import { Materi } from '../types';

interface CalendarModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (date: Date) => void;
  initialDate?: Date;
}

const CalendarModal: React.FC<CalendarModalProps> = ({ isOpen, onClose, onSelect, initialDate }) => {
  const safeInitialDate = initialDate && !isNaN(initialDate.getTime()) ? initialDate : new Date();
  const [currentViewDate, setCurrentViewDate] = useState(safeInitialDate);
  const [selectedDate, setSelectedDate] = useState(safeInitialDate);

  if (!isOpen) return null;

  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
  const daysShort = ["S", "M", "T", "W", "T", "F", "S"];

  const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const getFirstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const handlePrevMonth = () => {
    setCurrentViewDate(new Date(currentViewDate.getFullYear(), currentViewDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCurrentViewDate(new Date(currentViewDate.getFullYear(), currentViewDate.getMonth() + 1, 1));
  };

  const days = [];
  const firstDay = getFirstDayOfMonth(currentViewDate.getFullYear(), currentViewDate.getMonth());
  const daysInMonth = getDaysInMonth(currentViewDate.getFullYear(), currentViewDate.getMonth());

  for (let i = 0; i < firstDay; i++) {
    days.push(<div key={`empty-${i}`} className="w-10 h-10"></div>);
  }

  for (let d = 1; d <= daysInMonth; d++) {
    const isSelected = selectedDate.getDate() === d && 
                       selectedDate.getMonth() === currentViewDate.getMonth() && 
                       selectedDate.getFullYear() === currentViewDate.getFullYear();
    const isToday = new Date().getDate() === d && 
                    new Date().getMonth() === currentViewDate.getMonth() && 
                    new Date().getFullYear() === currentViewDate.getFullYear();

    days.push(
      <button
        key={d}
        onClick={() => setSelectedDate(new Date(currentViewDate.getFullYear(), currentViewDate.getMonth(), d, selectedDate.getHours(), selectedDate.getMinutes()))}
        className={`w-10 h-10 flex items-center justify-center rounded-full text-sm transition-colors ${
          isSelected 
            ? 'bg-[#6200ee] text-white font-bold' 
            : isToday 
              ? 'text-[#6200ee] font-bold ring-1 ring-[#6200ee]' 
              : 'text-gray-700 hover:bg-gray-100'
        }`}
      >
        {d}
      </button>
    );
  }

  const formatHeaderDate = (date: Date) => {
    if (isNaN(date.getTime())) return 'Invalid Date';
    return date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-lg shadow-2xl overflow-hidden w-full max-w-[320px] animate-in fade-in zoom-in duration-200">
        <div className="bg-[#6200ee] p-6 text-white">
          <div className="text-[10px] uppercase tracking-wider opacity-80 mb-6 font-medium">Select Date</div>
          <div className="flex justify-between items-center">
            <div className="text-3xl font-light">{formatHeaderDate(selectedDate)}</div>
            <Edit2 className="w-5 h-5 opacity-80 cursor-pointer hover:opacity-100" />
          </div>
        </div>

        <div className="p-4">
          <div className="flex justify-between items-center mb-4 px-2">
            <div className="text-sm font-medium text-gray-700">
              {monthNames[currentViewDate.getMonth()]} {currentViewDate.getFullYear()}
            </div>
            <div className="flex gap-2">
              <button onClick={handlePrevMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors text-gray-500"><ChevronLeft className="w-5 h-5" /></button>
              <button onClick={handleNextMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors text-gray-500"><ChevronRight className="w-5 h-5" /></button>
            </div>
          </div>

          <div className="grid grid-cols-7 text-center mb-2">
            {daysShort.map((day, i) => (
              <div key={i} className="text-[10px] font-medium text-gray-400 uppercase">{day}</div>
            ))}
          </div>

          <div className="grid grid-cols-7 gap-y-1 justify-items-center">
            {days}
          </div>
        </div>

        <div className="flex justify-end gap-4 p-4 text-xs font-bold">
          <button onClick={onClose} className="text-[#6200ee] uppercase tracking-wider px-2 py-1 hover:bg-[#6200ee]/5 rounded transition-colors">Cancel</button>
          <button 
            onClick={() => {
              onSelect(selectedDate);
              onClose();
            }} 
            className="text-[#6200ee] uppercase tracking-wider px-2 py-1 hover:bg-[#6200ee]/5 rounded transition-colors"
          >
            OK
          </button>
        </div>
      </div>
    </div>
  );
};

export const MateriTab: React.FC = () => {
  const [schedule, setSchedule] = useState<Materi[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [isDirty, setIsDirty] = useState(false);

  const [pickerOpen, setPickerOpen] = useState(false);
  const [activePickerIdx, setActivePickerIdx] = useState<number | null>(null);

  useEffect(() => {
    loadSchedule();
  }, []);

  const loadSchedule = async () => {
    setLoading(true);
    try {
      const data = await api.getAllData('Materi');
      setSchedule(data || []);
      setIsDirty(false);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = () => {
    setSchedule([...schedule, { Materi: "New Topic", Tanggal: new Date().toISOString() }]);
    setIsDirty(true);
  };

  const handleChange = (index: number, field: keyof Materi, val: any) => {
    const updated = [...schedule];
    updated[index] = { ...updated[index], [field]: val };
    setSchedule(updated);
    setIsDirty(true);
  };

  const handleDelete = (index: number) => {
    const updated = schedule.filter((_, i) => i !== index);
    setSchedule(updated);
    setIsDirty(true);
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await api.saveMateriList(schedule);
      setIsDirty(false);
      await loadSchedule();
      alert("Schedule saved! Calendar and Folders will sync shortly.");
    } catch (error) {
      alert("Failed to save schedule.");
    } finally {
      setSaving(false);
    }
  };

  const formatDisplayDate = (dateVal: string | Date) => {
    if (!dateVal) return 'Pick Date';
    try {
      const d = new Date(dateVal);
      if (isNaN(d.getTime())) return 'Pick Date';
      return d.toLocaleDateString('en-US', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
    } catch {
      return 'Pick Date';
    }
  };

  const openPicker = (idx: number) => {
    setActivePickerIdx(idx);
    setPickerOpen(true);
  };

  const handlePickerSelect = (date: Date) => {
    if (activePickerIdx !== null && schedule[activePickerIdx]) {
      const currentVal = schedule[activePickerIdx].Tanggal;
      const current = currentVal ? new Date(currentVal) : new Date();
      if (!isNaN(current.getTime())) {
        date.setHours(current.getHours());
        date.setMinutes(current.getMinutes());
      }
      handleChange(activePickerIdx, 'Tanggal', date.toISOString());
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col h-[calc(100vh-12rem)]">
      <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 rounded-t-xl">
        <h3 className="font-semibold text-gray-700 flex items-center gap-2">
          <Calendar className="w-4 h-4" /> Training Schedule
        </h3>
        <div className="flex gap-2">
          <button 
            onClick={handleAdd}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 text-gray-700"
          >
            <Plus className="w-4 h-4" /> Add Event
          </button>
          <button 
            onClick={handleSave} 
            disabled={!isDirty || saving}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              isDirty 
                ? 'bg-blue-600 text-white hover:bg-blue-700' 
                : 'bg-gray-200 text-gray-400 cursor-not-allowed'
            }`}
          >
            <Save className="w-4 h-4" />
            {saving ? 'Saving...' : 'Save & Sync'}
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4">
        {loading ? (
          <div className="flex justify-center items-center h-full py-12 text-gray-400 italic">
            <Loader2 className="w-5 h-5 animate-spin mr-2" /> Loading schedule...
          </div>
        ) : (
          <table className="w-full text-sm text-left text-gray-500">
            <thead className="text-xs text-gray-700 uppercase bg-gray-50 sticky top-0 z-10 shadow-sm">
              <tr>
                <th scope="col" className="px-4 py-3 w-1/3 rounded-tl-lg">Topic (Materi)</th>
                <th scope="col" className="px-4 py-3 w-1/4">Date & Time</th>
                <th scope="col" className="px-4 py-3">Drive Link</th>
                <th scope="col" className="px-4 py-3 w-16 text-right rounded-tr-lg">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {schedule.map((item, idx) => {
                if (!item) return null;
                const d = item.Tanggal ? new Date(item.Tanggal) : null;
                const timeValue = d && !isNaN(d.getTime()) ? d.toTimeString().slice(0, 5) : "09:00";

                return (
                  <tr key={idx} className="bg-white hover:bg-gray-50 group transition-colors">
                    <td className="px-4 py-3 align-top">
                      <input
                        type="text"
                        value={item.Materi || ""}
                        onChange={(e) => handleChange(idx, 'Materi', e.target.value)}
                        className="w-full bg-transparent font-medium border-b border-transparent hover:border-gray-300 focus:border-blue-500 rounded-sm px-1 py-1 focus:outline-none transition-all text-gray-900"
                        placeholder="Enter topic..."
                      />
                    </td>
                    <td className="px-4 py-3 align-top">
                      <div className="max-w-[220px] space-y-2">
                        <button 
                          onClick={() => openPicker(idx)}
                          className="w-full flex items-center gap-3 px-3 py-2.5 bg-white border border-gray-200 rounded-lg text-gray-800 text-sm hover:border-blue-500 focus:ring-2 focus:ring-blue-500/20 outline-none transition-all shadow-sm"
                        >
                          <Calendar className="w-4 h-4 text-gray-400" />
                          {formatDisplayDate(item.Tanggal)}
                        </button>

                        <div className="flex items-center gap-2 pl-1">
                          <Clock className="w-3.5 h-3.5 text-gray-400" />
                          <input 
                            type="time" 
                            value={timeValue}
                            onChange={(e) => {
                              const [h, m] = e.target.value.split(':');
                              const d = item.Tanggal ? new Date(item.Tanggal) : new Date();
                              d.setHours(parseInt(h), parseInt(m));
                              handleChange(idx, 'Tanggal', d.toISOString());
                            }}
                            className="bg-transparent text-xs text-gray-500 focus:outline-none border-none p-0 cursor-pointer hover:text-blue-600"
                          />
                          <span className="text-[10px] text-gray-300 font-light">•</span>
                          <span className="text-[10px] text-gray-400">{item.CalendarStatus || 'Pending Sync'}</span>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 py-3 align-middle">
                      {item.GDrive ? (
                        <a 
                          href={item.GDrive} 
                          target="_blank" 
                          rel="noreferrer"
                          className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-blue-50 text-blue-700 rounded-full text-xs font-medium hover:bg-blue-100 transition-colors"
                        >
                          <ExternalLink className="w-3 h-3" /> View Folder
                        </a>
                      ) : (
                        <span className="text-xs text-gray-400 italic px-2">Synced automatically</span>
                      )}
                    </td>
                    <td className="px-4 py-3 text-right align-middle">
                      <button 
                        onClick={() => handleDelete(idx)}
                        className="text-gray-300 hover:text-red-600 p-2 hover:bg-red-50 rounded-lg transition-colors"
                        title="Remove Event"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
              {schedule.length === 0 && (
                 <tr>
                    <td colSpan={4} className="px-4 py-12 text-center text-gray-400 italic">No scheduled topics. Add one to get started.</td>
                 </tr>
              )}
            </tbody>
          </table>
        )}
      </div>

      <CalendarModal 
        isOpen={pickerOpen}
        onClose={() => setPickerOpen(false)}
        initialDate={activePickerIdx !== null && schedule[activePickerIdx] && schedule[activePickerIdx].Tanggal ? new Date(schedule[activePickerIdx].Tanggal) : new Date()}
        onSelect={handlePickerSelect}
      />
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Loader2, Check, X, Mail, ChevronDown } from 'lucide-react';
import { api } from '../services/api';
import { DashboardStats, Materi, RecapRow } from '../types';

export const DashboardTab: React.FC = () => {
  const [materiList, setMateriList] = useState<Materi[]>([]);
  const [selectedMateri, setSelectedMateri] = useState<string>('');
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [participants, setParticipants] = useState<RecapRow[]>([]);
  const [loading, setLoading] = useState(false);
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [dropdownOpen, setDropdownOpen] = useState(false);

  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const fetchMateri = async () => {
      try {
        const data = await api.getAllData('Materi');
        const sorted = (data || [])
          .filter(m => m && m.Materi)
          .sort((a, b) => a.Materi.localeCompare(b.Materi));
        setMateriList(sorted);
        if (sorted.length > 0 && sorted[0]) setSelectedMateri(sorted[0].Materi);
      } catch (error) {
        console.error("Error fetching materi:", error);
      }
    };
    fetchMateri();

    const handleClickOutside = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (!selectedMateri) return;
    const fetchData = async () => {
      setLoading(true);
      try {
        const [statsData, partsData] = await Promise.all([
          api.getRecapDashboardData(selectedMateri),
          api.getParticipantsByCourse(selectedMateri)
        ]);
        setStats(statsData);
        setParticipants(partsData || []);
      } catch (error) {
        console.error("Error fetching dashboard data:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [selectedMateri]);

  const handleAttendance = async (teacherEmail: string, status: 'Hadir' | 'Tidak hadir') => {
    setUpdatingId(teacherEmail);
    try {
      await api.updateAttendance({ teacherEmail, courseTitle: selectedMateri, status });

      const updatedParticipants = participants.map(p => {
        if (p.Email === teacherEmail) return { ...p, Attendance: status };
        return p;
      });
      setParticipants(updatedParticipants);

      if (stats) {
        const newStats = { ...stats };
        if (status === 'Hadir') newStats.attended++;
        if (status === 'Tidak hadir') newStats.absent++;
        setStats(newStats);
      }
    } catch (error) {
      alert("Failed to update attendance.");
    } finally {
      setUpdatingId(null);
    }
  };

  const chartData = stats ? [
    { name: 'Registered', value: stats.totalRegistered || 0, color: '#3b82f6' },
    { name: 'Pending', value: Math.max(0, (stats.totalRegistered || 0) - (stats.attended || 0) - (stats.absent || 0)), color: '#f59e0b' },
    { name: 'Attended', value: stats.attended || 0, color: '#22c55e' },
    { name: 'Absent', value: stats.absent || 0, color: '#ef4444' },
  ] : [];

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Training Dashboard</h2>
          <p className="text-gray-500 text-sm">Overview of attendance and registration stats.</p>
        </div>

        <div className="relative" ref={dropdownRef}>
          <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl shadow-sm border border-gray-200">
            <span className="text-sm font-semibold text-gray-500">Filter:</span>
            <button 
              onClick={() => setDropdownOpen(!dropdownOpen)}
              className="flex items-center gap-2 text-sm font-bold text-gray-800 min-w-[160px] justify-between focus:outline-none"
            >
              <span className="truncate">{selectedMateri || 'Select Topic'}</span>
              <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${dropdownOpen ? 'rotate-180' : ''}`} />
            </button>
          </div>

          {dropdownOpen && (
            <div className="absolute right-0 mt-2 w-full min-w-[220px] bg-white border border-gray-100 rounded-xl shadow-xl z-50 py-1 animate-in fade-in slide-in-from-top-2 duration-200">
              {materiList.map((m, idx) => {
                if (!m) return null;
                return (
                  <button
                    key={idx}
                    onClick={() => {
                      setSelectedMateri(m.Materi);
                      setDropdownOpen(false);
                    }}
                    className={`w-full text-left px-4 py-2.5 text-sm hover:bg-gray-50 transition-colors ${
                      selectedMateri === m.Materi ? 'text-blue-600 font-bold bg-blue-50/50' : 'text-gray-700'
                    }`}
                  >
                    {m.Materi}
                  </button>
                );
              })}
              {materiList.length === 0 && (
                <div className="px-4 py-2.5 text-sm text-gray-400 italic">No topics found.</div>
              )}
            </div>
          )}
        </div>
      </div>

      {loading && !stats ? (
        <div className="h-64 flex items-center justify-center">
          <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
        </div>
      ) : stats ? (
        <>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <StatCard label="Total Registered" value={stats.totalRegistered} color="bg-blue-50 text-blue-700" />
            <StatCard label="Pending Attendance" value={Math.max(0, stats.totalRegistered - stats.attended - stats.absent)} color="bg-amber-50 text-amber-700" />
            <StatCard label="Attended" value={stats.attended} color="bg-green-50 text-green-700" />
            <StatCard label="Absent" value={stats.absent} color="bg-red-50 text-red-700" />
          </div>

          <div className="grid md:grid-cols-3 gap-6">
            <div className="md:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-gray-200">
              <h3 className="text-lg font-semibold mb-4 text-gray-800">Participation Overview</h3>
              <div className="h-64 w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={chartData}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <XAxis dataKey="name" tick={{fontSize: 10}} />
                    <YAxis allowDecimals={false} tick={{fontSize: 10}} />
                    <Tooltip 
                      cursor={{fill: '#f3f4f6'}}
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)', fontSize: '12px' }}
                    />
                    <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="md:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
               <div className="p-6 border-b border-gray-100">
                  <h3 className="text-lg font-semibold text-gray-800">Participant List</h3>
                  <p className="text-sm text-gray-500">Manage attendance for {selectedMateri}</p>
               </div>
               <div className="flex-1 overflow-y-auto max-h-[500px]">
                 <table className="w-full text-sm text-left text-gray-500">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 sticky top-0">
                      <tr>
                        <th className="px-6 py-3">Teacher</th>
                        <th className="px-6 py-3">Confirmation</th>
                        <th className="px-6 py-3 text-right">Attendance</th>
                      </tr>
                    </thead>
                    <tbody>
                      {participants.map((p, idx) => {
                        if (!p) return null;
                        return (
                          <tr key={idx} className="bg-white border-b hover:bg-gray-50">
                            <td className="px-6 py-4 font-medium text-gray-900">
                              {p.Teacher || "Unknown"}
                              <div className="text-xs text-gray-500 font-normal">{p.Email || ""}</div>
                            </td>
                            <td className="px-6 py-4">
                               <span className="inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-[10px] font-medium bg-blue-100 text-blue-800">
                                 <Mail className="w-3 h-3" /> Email Sent
                               </span>
                            </td>
                            <td className="px-6 py-4 text-right">
                               {p.Attendance ? (
                                 <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-[10px] font-medium ${
                                   p.Attendance === 'Hadir' 
                                    ? 'bg-green-100 text-green-800' 
                                    : 'bg-red-100 text-red-800'
                                 }`}>
                                   {p.Attendance === 'Hadir' ? 'Present' : 'Absent'}
                                 </span>
                               ) : (
                                 <div className="flex justify-end gap-2">
                                    {updatingId === p.Email ? (
                                      <Loader2 className="w-5 h-5 animate-spin text-blue-600" />
                                    ) : (
                                      <>
                                        <button 
                                          onClick={() => handleAttendance(p.Email, 'Hadir')}
                                          className="p-1.5 text-green-600 hover:bg-green-100 rounded-md transition-colors" 
                                          title="Mark Present"
                                        >
                                          <Check className="w-5 h-5" />
                                        </button>
                                        <button 
                                          onClick={() => handleAttendance(p.Email, 'Tidak hadir')}
                                          className="p-1.5 text-red-600 hover:bg-red-100 rounded-md transition-colors"
                                          title="Mark Absent"
                                        >
                                          <X className="w-5 h-5" />
                                        </button>
                                      </>
                                    )}
                                 </div>
                               )}
                            </td>
                          </tr>
                        );
                      })}
                      {participants.length === 0 && (
                        <tr>
                          <td colSpan={3} className="px-6 py-8 text-center text-gray-400">
                            No participants registered yet.
                          </td>
                        </tr>
                      )}
                    </tbody>
                 </table>
               </div>
            </div>
          </div>
        </>
      ) : (
        <div className="text-center py-12 text-gray-500">No data available for this topic.</div>
      )}
    </div>
  );
};

const StatCard = ({ label, value, color }: { label: string, value: number, color: string }) => (
  <div className={`p-4 rounded-xl border border-transparent ${color}`}>
    <div className="text-[10px] font-medium opacity-80 uppercase tracking-wider">{label}</div>
    <div className="text-2xl font-bold mt-1">{value || 0}</div>
  </div>
);

import React, { useEffect, useState } from 'react';
// Added Loader2 to fix the 'Cannot find name Loader2' error on line 240
import { Plus, Trash2, Save, Calendar, ExternalLink, Clock, ChevronLeft, ChevronRight, Edit2, Loader2 } from 'lucide-react';
import { api } from '../services/api';
import { Materi } from '../types';

interface CalendarModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (date: Date) => void;
  initialDate?: Date;
}

const CalendarModal: React.FC<CalendarModalProps> = ({ isOpen, onClose, onSelect, initialDate }) => {
  const safeInitialDate = initialDate && !isNaN(initialDate.getTime()) ? initialDate : new Date();
  const [currentViewDate, setCurrentViewDate] = useState(safeInitialDate);
  const [selectedDate, setSelectedDate] = useState(safeInitialDate);

  if (!isOpen) return null;

  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
  const daysShort = ["S", "M", "T", "W", "T", "F", "S"];

  const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const getFirstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const handlePrevMonth = () => {
    setCurrentViewDate(new Date(currentViewDate.getFullYear(), currentViewDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCurrentViewDate(new Date(currentViewDate.getFullYear(), currentViewDate.getMonth() + 1, 1));
  };

  const days = [];
  const firstDay = getFirstDayOfMonth(currentViewDate.getFullYear(), currentViewDate.getMonth());
  const daysInMonth = getDaysInMonth(currentViewDate.getFullYear(), currentViewDate.getMonth());

  for (let i = 0; i < firstDay; i++) {
    days.push(<div key={`empty-${i}`} className="w-10 h-10"></div>);
  }

  for (let d = 1; d <= daysInMonth; d++) {
    const isSelected = selectedDate.getDate() === d && 
                       selectedDate.getMonth() === currentViewDate.getMonth() && 
                       selectedDate.getFullYear() === currentViewDate.getFullYear();
    const isToday = new Date().getDate() === d && 
                    new Date().getMonth() === currentViewDate.getMonth() && 
                    new Date().getFullYear() === currentViewDate.getFullYear();

    days.push(
      <button
        key={d}
        onClick={() => setSelectedDate(new Date(currentViewDate.getFullYear(), currentViewDate.getMonth(), d, selectedDate.getHours(), selectedDate.getMinutes()))}
        className={`w-10 h-10 flex items-center justify-center rounded-full text-sm transition-colors ${
          isSelected 
            ? 'bg-[#6200ee] text-white font-bold' 
            : isToday 
              ? 'text-[#6200ee] font-bold ring-1 ring-[#6200ee]' 
              : 'text-gray-700 hover:bg-gray-100'
        }`}
      >
        {d}
      </button>
    );
  }

  const formatHeaderDate = (date: Date) => {
    if (isNaN(date.getTime())) return 'Invalid Date';
    return date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-lg shadow-2xl overflow-hidden w-full max-w-[320px] animate-in fade-in zoom-in duration-200">
        <div className="bg-[#6200ee] p-6 text-white">
          <div className="text-[10px] uppercase tracking-wider opacity-80 mb-6 font-medium">Select Date</div>
          <div className="flex justify-between items-center">
            <div className="text-3xl font-light">{formatHeaderDate(selectedDate)}</div>
            <Edit2 className="w-5 h-5 opacity-80 cursor-pointer hover:opacity-100" />
          </div>
        </div>

        <div className="p-4">
          <div className="flex justify-between items-center mb-4 px-2">
            <div className="text-sm font-medium text-gray-700">
              {monthNames[currentViewDate.getMonth()]} {currentViewDate.getFullYear()}
            </div>
            <div className="flex gap-2">
              <button onClick={handlePrevMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors text-gray-500"><ChevronLeft className="w-5 h-5" /></button>
              <button onClick={handleNextMonth} className="p-1 hover:bg-gray-100 rounded-full transition-colors text-gray-500"><ChevronRight className="w-5 h-5" /></button>
            </div>
          </div>

          <div className="grid grid-cols-7 text-center mb-2">
            {daysShort.map((day, i) => (
              <div key={i} className="text-[10px] font-medium text-gray-400 uppercase">{day}</div>
            ))}
          </div>

          <div className="grid grid-cols-7 gap-y-1 justify-items-center">
            {days}
          </div>
        </div>

        <div className="flex justify-end gap-4 p-4 text-xs font-bold">
          <button onClick={onClose} className="text-[#6200ee] uppercase tracking-wider px-2 py-1 hover:bg-[#6200ee]/5 rounded transition-colors">Cancel</button>
          <button 
            onClick={() => {
              onSelect(selectedDate);
              onClose();
            }} 
            className="text-[#6200ee] uppercase tracking-wider px-2 py-1 hover:bg-[#6200ee]/5 rounded transition-colors"
          >
            OK
          </button>
        </div>
      </div>
    </div>
  );
};

export const MateriTab: React.FC = () => {
  const [schedule, setSchedule] = useState<Materi[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [isDirty, setIsDirty] = useState(false);

  const [pickerOpen, setPickerOpen] = useState(false);
  const [activePickerIdx, setActivePickerIdx] = useState<number | null>(null);

  useEffect(() => {
    loadSchedule();
  }, []);

  const loadSchedule = async () => {
    setLoading(true);
    try {
      const data = await api.getAllData('Materi');
      setSchedule(data || []);
      setIsDirty(false);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleAdd = () => {
    setSchedule([...schedule, { Materi: "New Topic", Tanggal: new Date().toISOString() }]);
    setIsDirty(true);
  };

  const handleChange = (index: number, field: keyof Materi, val: any) => {
    const updated = [...schedule];
    updated[index] = { ...updated[index], [field]: val };
    setSchedule(updated);
    setIsDirty(true);
  };

  const handleDelete = (index: number) => {
    const updated = schedule.filter((_, i) => i !== index);
    setSchedule(updated);
    setIsDirty(true);
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      await api.saveMateriList(schedule);
      setIsDirty(false);
      await loadSchedule();
      alert("Schedule saved! Calendar and Folders will sync shortly.");
    } catch (error) {
      alert("Failed to save schedule.");
    } finally {
      setSaving(false);
    }
  };

  const formatDisplayDate = (dateVal: string | Date) => {
    if (!dateVal) return 'Pick Date';
    try {
      const d = new Date(dateVal);
      if (isNaN(d.getTime())) return 'Pick Date';
      return d.toLocaleDateString('en-US', { year: 'numeric', month: '2-digit', day: '2-digit' }).replace(/\//g, '-');
    } catch {
      return 'Pick Date';
    }
  };

  const openPicker = (idx: number) => {
    setActivePickerIdx(idx);
    setPickerOpen(true);
  };

  const handlePickerSelect = (date: Date) => {
    if (activePickerIdx !== null && schedule[activePickerIdx]) {
      const currentVal = schedule[activePickerIdx].Tanggal;
      const current = currentVal ? new Date(currentVal) : new Date();
      if (!isNaN(current.getTime())) {
        date.setHours(current.getHours());
        date.setMinutes(current.getMinutes());
      }
      handleChange(activePickerIdx, 'Tanggal', date.toISOString());
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col h-[calc(100vh-12rem)]">
      <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 rounded-t-xl">
        <h3 className="font-semibold text-gray-700 flex items-center gap-2">
          <Calendar className="w-4 h-4" /> Training Schedule
        </h3>
        <div className="flex gap-2">
          <button 
            onClick={handleAdd}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium hover:bg-gray-50 text-gray-700"
          >
            <Plus className="w-4 h-4" /> Add Event
          </button>
          <button 
            onClick={handleSave} 
            disabled={!isDirty || saving}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              isDirty 
                ? 'bg-blue-600 text-white hover:bg-blue-700' 
                : 'bg-gray-200 text-gray-400 cursor-not-allowed'
            }`}
          >
            <Save className="w-4 h-4" />
            {saving ? 'Saving...' : 'Save & Sync'}
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4">
        {loading ? (
          <div className="flex justify-center items-center h-full py-12 text-gray-400 italic">
            <Loader2 className="w-5 h-5 animate-spin mr-2" /> Loading schedule...
          </div>
        ) : (
          <table className="w-full text-sm text-left text-gray-500">
            <thead className="text-xs text-gray-700 uppercase bg-gray-50 sticky top-0 z-10 shadow-sm">
              <tr>
                <th scope="col" className="px-4 py-3 w-1/3 rounded-tl-lg">Topic (Materi)</th>
                <th scope="col" className="px-4 py-3 w-1/4">Date & Time</th>
                <th scope="col" className="px-4 py-3">Drive Link</th>
                <th scope="col" className="px-4 py-3 w-16 text-right rounded-tr-lg">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {schedule.map((item, idx) => {
                if (!item) return null;
                const d = item.Tanggal ? new Date(item.Tanggal) : null;
                const timeValue = d && !isNaN(d.getTime()) ? d.toTimeString().slice(0, 5) : "09:00";

                return (
                  <tr key={idx} className="bg-white hover:bg-gray-50 group transition-colors">
                    <td className="px-4 py-3 align-top">
                      <input
                        type="text"
                        value={item.Materi || ""}
                        onChange={(e) => handleChange(idx, 'Materi', e.target.value)}
                        className="w-full bg-transparent font-medium border-b border-transparent hover:border-gray-300 focus:border-blue-500 rounded-sm px-1 py-1 focus:outline-none transition-all text-gray-900"
                        placeholder="Enter topic..."
                      />
                    </td>
                    <td className="px-4 py-3 align-top">
                      <div className="max-w-[220px] space-y-2">
                        <button 
                          onClick={() => openPicker(idx)}
                          className="w-full flex items-center gap-3 px-3 py-2.5 bg-white border border-gray-200 rounded-lg text-gray-800 text-sm hover:border-blue-500 focus:ring-2 focus:ring-blue-500/20 outline-none transition-all shadow-sm"
                        >
                          <Calendar className="w-4 h-4 text-gray-400" />
                          {formatDisplayDate(item.Tanggal)}
                        </button>

                        <div className="flex items-center gap-2 pl-1">
                          <Clock className="w-3.5 h-3.5 text-gray-400" />
                          <input 
                            type="time" 
                            value={timeValue}
                            onChange={(e) => {
                              const [h, m] = e.target.value.split(':');
                              const d = item.Tanggal ? new Date(item.Tanggal) : new Date();
                              d.setHours(parseInt(h), parseInt(m));
                              handleChange(idx, 'Tanggal', d.toISOString());
                            }}
                            className="bg-transparent text-xs text-gray-500 focus:outline-none border-none p-0 cursor-pointer hover:text-blue-600"
                          />
                          <span className="text-[10px] text-gray-300 font-light">•</span>
                          <span className="text-[10px] text-gray-400">{item.CalendarStatus || 'Pending Sync'}</span>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 py-3 align-middle">
                      {item.GDrive ? (
                        <a 
                          href={item.GDrive} 
                          target="_blank" 
                          rel="noreferrer"
                          className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-blue-50 text-blue-700 rounded-full text-xs font-medium hover:bg-blue-100 transition-colors"
                        >
                          <ExternalLink className="w-3 h-3" /> View Folder
                        </a>
                      ) : (
                        <span className="text-xs text-gray-400 italic px-2">Synced automatically</span>
                      )}
                    </td>
                    <td className="px-4 py-3 text-right align-middle">
                      <button 
                        onClick={() => handleDelete(idx)}
                        className="text-gray-300 hover:text-red-600 p-2 hover:bg-red-50 rounded-lg transition-colors"
                        title="Remove Event"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                );
              })}
              {schedule.length === 0 && (
                 <tr>
                    <td colSpan={4} className="px-4 py-12 text-center text-gray-400 italic">No scheduled topics. Add one to get started.</td>
                 </tr>
              )}
            </tbody>
          </table>
        )}
      </div>

      <CalendarModal 
        isOpen={pickerOpen}
        onClose={() => setPickerOpen(false)}
        initialDate={activePickerIdx !== null && schedule[activePickerIdx] && schedule[activePickerIdx].Tanggal ? new Date(schedule[activePickerIdx].Tanggal) : new Date()}
        onSelect={handlePickerSelect}
      />
    </div>
  );
};

